example.code:
// Creating a found result
var found = ArrayElementInfo<string>.Found(2, "hello", 5);
if (found) // implicit bool conversion
{
    Console.WriteLine($"Found at index {(uint?)found}"); // explicit uint? conversion
}

// Creating a not-found result
var notFound = ArrayElementInfo<string>.NotFound("missing", 5);

// Using TryGetElement pattern
if (found.TryGetElement(out var element, out var index))
{
    Console.WriteLine($"Element '{element}' at index {index}");
}

// Using deconstruction
var (idx, elem, len) = found;

var info = ArrayElementInfo<string>.Found(0, "hello", 5);
if (info) // implicit conversion to bool
{
    Console.WriteLine("Found!");
}

var found = ArrayElementInfo<string>.Found(2, "hello", 10);
// found.IsFound == true
// found.Index == 2
// found.Element == "hello"

var info = ArrayElementInfo<string>.Found(2, "hello", 5);
if (info.TryGetElement(out var element, out var index))
{
    Console.WriteLine($"Found '{element}' at index {index}");
}

var found = ArrayElementInfo<int>.Found(0, 42, 5);
int value = found.GetElementOrDefault(); // returns 42

var notFound = ArrayElementInfo<int>.NotFound(42, 5);
int missing = notFound.GetElementOrDefault(); // returns 0

// Result-based (no exceptions thrown)
var (success, value) = Try.TryGet(() => ParseData());
if (success) { /* use value */ }

// Exception-based (throws on error)
var result = Try.Get(() => ParseData());

// With fallback value
var result = Try.GetOrDefault(() => ParseData(), defaultValue);

// With exception transformation
var result = Try.Get(() => ParseData(), ex => new DataException("Parse failed", ex));

// With logging callback
var result = Try.Get(() => ParseData(), onException: ex => _logger.LogError(ex, "Parse failed"));

// Async with cancellation
var result = await Try.GetAsync(ct => FetchDataAsync(ct), cancellationToken: cts.Token);

